var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 알아 봤나?","JPN":"それで、調べはついたのかな？","ENG":"So, what did you find out?","TWN":"都打聽好了嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"짐작하셨던 대로 연구원은 제프티 바이오테크 소속이었습니다.","JPN":"予想どおり研究員はジェフティ・バイオテック所属でした。","ENG":"As you have guessed, the researcher was from Jehuty Biotech.","TWN":"正如老闆說的，研究員是傑夫堤生物科技的人沒錯。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실토한 정보를 토대로 실험실을 찾았지만, 이미 텅 비어 있었다더군요.","JPN":"自白した情報をもとに実験室を見つけましたが、すでにもぬけの殻だったそうです。","ENG":"We located its testing lab based on his testimony, but... it was empty.","TWN":"我們照著他所說的找到了實驗室，但早已人去樓空。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 정도 규모의 시설을 정리할 정도라면, 진작에 떠날 준비를 하고 있었던 거겠죠.","JPN":"あの規模の施設をすぐ移転したということは、早い段階で準備をしていたのでしょうね。","ENG":"Given the size of the facility, the staff has to have prepared to leave for a long time.","TWN":"能在這麼短的時間內，將那裡的設備都清空，應該是早有預備。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아쉽게 됐군.","JPN":"残念だな。","ENG":"What a shame.","TWN":"真可惜！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만, 미처 지우지 못한 흔적이 남아 있었습니다.","JPN":"ですが、消し切れなかった痕跡が残っていました。","ENG":"But it couldn't erase all its traces before it left.","TWN":"但凡走過必留下痕跡。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흔적?","JPN":"痕跡？","ENG":"Traces?","TWN":"什麼痕跡？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"메이즈 전대원들이 잔류 침식파를 분석해 봤습니다만…….","JPN":"メイズ戦隊員たちが残留侵食波を分析してみたのですが……","ENG":"The members of the Maze Division analyzed the remaining Corruption rays,","TWN":"梅茲戰隊的隊員分析了殘留的侵蝕波……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 결과가 나왔다더군요.","JPN":"このような結果が出たそうです。","ENG":"and they've got these results.","TWN":"發現這樣的結果。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그림자가 다녀갔군.","JPN":"シャドウがいたようだな。","ENG":"A Shadow was there.","TWN":"有暗影的痕跡嗎？！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼에도 파괴의 흔적조차 없었다는 건…….","JPN":"なのに破壊の痕跡すらなかったということは……","ENG":"But no traces of destruction.","TWN":"但是卻沒有破壞的痕跡……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 그림자가 기업에 적대적이지 않았다는 뜻이죠.","JPN":"そのシャドウは企業に対して敵対的ではなかった、という意味でしょう。","ENG":"It means that Shadow isn't hostile to this company.","TWN":"意思就是那個暗影和企業不是敵對關係吧？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제프티 바이오테크가 그들과 관련되어 있다고 하면 그림이 명확해지는군요.","JPN":"ジェフティ・バイオテックが彼らと関係があるとしたら、魂胆が見えてきますね。","ENG":"Jehuty Biotech's relation to them brings the puzzle pieces together.","TWN":"傑夫堤生物科技和他們有關的話，那輪廓就越來越清晰囉！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"A 타입을 다시 생산 중이던 것도 그렇고, 저희 기대와 달리 쉽게 발을 뺄 생각이 없나 봅니다.","JPN":"Aタイプを再び生産していたのもそうですし、私たちの期待と裏腹に、簡単に手を引くつもりはないようです。","ENG":"It's reproducing Type A, too. It's not planning to stop anytime soon, unlike we hoped it would.","TWN":"他們可能又在生產A類，沒打算輕易收手的意思。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음……. 뭐, 짐작은 했네만……","JPN":"ふむ……まあ、予測はしていたが……","ENG":"Hmm... Well, I figured much...","TWN":"嗯……雖然是在預料之中……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 이건, 증언을 토대로 만든 제프티 바이오테크 대표의 몽타주입니다.","JPN":"そしてこれは、証言をもとに作ったジェフティ・バイオテック代表のモンタージュです。","ENG":"And this is a montage of Jehuty Biotech CEO created based on witness accounts.","TWN":"另外，這是根據研究員的描述，繪製出的傑夫堤生物科技代表的畫像。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"얼굴을 드러내지 않은지 오래되었다고 하니, 확신은 하기 어렵겠지만요.","JPN":"長い間顔を出していないそうで、確信はできませんが。","ENG":"It may not be accurate since he hasn't been seen in public for a long time.","TWN":"只是據說他已經許久未露面，所以也不太確定是不是長這樣。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군. 확인해 줘서 고맙네.","JPN":"……そうか。確認してくれてありがとう。","ENG":"... I see. Thank you for checking all this.","TWN":"……明白，謝謝你的調查。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};